export const PermissionErrorCode = new Set([403, 403_001]);

interface SsoParams {
    appCode: string
}

/**
 * 存在前后端使用
 */
export class SSOSDKClient {
    private readonly SSO_TICKET = 'spotter_sso_ticket';
    private appCode  = '';
    constructor({
        appCode,
    }:SsoParams) {
        this.appCode = appCode;
    }
    /**
     * 前端登出方法
     */
    logout() {
        const iamApiUrl = getAppBootData().iamApiUrl;
        window.location.replace(
            `${iamApiUrl}/sso/logout?callback=${encodeURIComponent(
                this.removeQueryParam(window.location.href, this.SSO_TICKET),
            )}&appCode=${this.appCode}`,
        );
    }
    /**
     * 登出跳转sso提示页面
     * @param i18key 提示
     */
    logoutWithInfo(i18key:string) {
        const iamApiUrl = getAppBootData().iamApiUrl;
        window.location.replace(
            `${iamApiUrl}/sso/auth/error?errorMessage=${i18key}&callback=${encodeURIComponent(
                    this.removeQueryParam(window.location.href, this.SSO_TICKET))}&appCode=${this.appCode}`,
        );
    }

    removeQueryParam = (url: string | URL, param: string) => {
        const urlObj = new URL(url);
        const searchParams = new URLSearchParams(urlObj.search);
        searchParams.delete(param);
        urlObj.search = searchParams.toString();
        return urlObj.toString();
    };
}
